const files = $input.item.json;
const pr = $input.item.json._pr || {};

// Get the PR data passed from previous node via $('Webhook - PR Opened')
const webhookData = $('Webhook - PR Opened').item.json.body;
const pullRequest = webhookData.pull_request;
const repo = webhookData.repository;

const filePaths = Array.isArray(files) ? files.map(f => f.filename) : [];

// Define critical path patterns and their owners
const CRITICAL_PATHS = [
  { pattern: /auth|login|oauth|jwt|session|password/i, zone: 'auth', reviewers: ['YOUR_SECURITY_REVIEWER'], label: 'needs-security-review', emoji: '🔐' },
  { pattern: /payment|billing|stripe|invoice|checkout|pricing/i, zone: 'payments', reviewers: ['YOUR_PAYMENTS_REVIEWER'], label: 'needs-payments-review', emoji: '💳' },
  { pattern: /\.env|config\.|secrets?\.|credentials?/i, zone: 'config', reviewers: ['YOUR_DEVOPS_REVIEWER'], label: 'needs-devops-review', emoji: '⚙️' },
  { pattern: /migration|schema\.sql|alembic|prisma.*schema/i, zone: 'database', reviewers: ['YOUR_DB_REVIEWER'], label: 'needs-db-review', emoji: '🗄️' },
  { pattern: /dockerfile|docker-compose|\.github\/workflows|ci\.yml|deploy/i, zone: 'infrastructure', reviewers: ['YOUR_DEVOPS_REVIEWER'], label: 'needs-infra-review', emoji: '🏗️' }
];

const triggered = [];
const allReviewers = new Set();
const labelsToAdd = ['review-required'];
let checklistItems = [];

for (const file of filePaths) {
  for (const rule of CRITICAL_PATHS) {
    if (rule.pattern.test(file)) {
      if (!triggered.find(t => t.zone === rule.zone)) {
        triggered.push({ ...rule, file });
        rule.reviewers.forEach(r => allReviewers.add(r));
        labelsToAdd.push(rule.label);
        checklistItems.push(`${rule.emoji} **${rule.zone.toUpperCase()}** — \`${file}\` touched. Requires review from: ${rule.reviewers.join(', ')}`);
      }
    }
  }
}

const isCritical = triggered.length > 0;
const riskLevel = triggered.length === 0 ? 'LOW' : triggered.length === 1 ? 'MEDIUM' : 'HIGH';
const riskEmoji = riskLevel === 'LOW' ? '🟢' : riskLevel === 'MEDIUM' ? '🟡' : '🔴';

const standardChecklist = [
  '- [ ] Tests added/updated',
  '- [ ] Documentation updated',
  '- [ ] No hardcoded secrets or credentials',
  '- [ ] Error handling considered',
  isCritical ? '- [ ] Security implications reviewed' : null,
  isCritical ? '- [ ] Rollback plan documented' : null
].filter(Boolean).join('\n');

const prBody = pullRequest.body || '';
const commentBody = `## ${riskEmoji} Automated PR Review Assessment\n\n**Risk Level:** ${riskLevel}\n**Files Changed:** ${filePaths.length}\n\n${isCritical ? `### ⚠️ Critical Areas Detected\n${checklistItems.join('\n')}\n\n` : ''}### Standard Checklist\n${standardChecklist}\n\n---\n*This comment was generated automatically by the PR Review Enforcer workflow.*`;

return [{
  json: {
    pr_number: pullRequest.number,
    pr_title: pullRequest.title,
    pr_url: pullRequest.html_url,
    pr_author: pullRequest.user.login,
    repo: repo.full_name,
    files_changed: filePaths.length,
    file_list: filePaths.slice(0, 10).join('\n'),
    is_critical: isCritical,
    risk_level: riskLevel,
    risk_emoji: riskEmoji,
    triggered_zones: triggered.map(t => t.zone).join(', ') || 'none',
    reviewers: [...allReviewers],
    labels_to_add: labelsToAdd,
    comment_body: commentBody,
    checklist_items: checklistItems.join('\n') || 'No critical areas detected.',
    discord_message: `${riskEmoji} **PR #${pullRequest.number} — ${riskLevel} RISK**\n**${pullRequest.title}**\nby \`${pullRequest.user.login}\` · ${filePaths.length} files changed\n${isCritical ? `⚠️ Critical zones: ${triggered.map(t => t.emoji + ' ' + t.zone).join(', ')}\n` : ''}🔗 ${pullRequest.html_url}`
  }
}];
